  String sql = "INSERT INTO users (username, password) VALUES (?, ?)";
  try (Connection conn = ...; PreparedStatement pstmt = conn.prepareStatement(sql)) {
      pstmt.setString(1, "foo");
      pstmt.setString(2, param);
